/**
    This allows us to load the IE polyfills via feature detection so that they do not load
    needlessly in the browsers that do not need them. It also ensures they are loaded
    non async so that they load before the rest of our JS.
*/
var head = document.getElementsByTagName('head')[0];
if (!window.CSS || !window.CSS.supports || !window.CSS.supports('--fake-var', 0)) {
    var script = document.createElement('script');
    script.setAttribute('src', "https://assets.apnews.com/resource/00000188-2a81-d28a-a1fd-7bfb6ccb0000/util/IEPolyfills.min.5da06518199a7f3c07c59ceef56b2229.gz.js");
    script.setAttribute('type', 'text/javascript');
    script.async = false;
    head.appendChild(script);
}

meta.script:
window.dataLayer = window.dataLayer || [];
(function () {
    // Get the content of the meta tag named "gtm-dataLayer" from the document's head, if it exists
    var dataValue = document.head.querySelector('meta[name="gtm-dataLayer"]')?.content;
    // Get the value of the attribute "data-named-page-type" from an element in the document, if it exists
    let pageType = document.querySelector('[data-named-page-type]')?.getAttribute('data-named-page-type')
    // If dataValue exists, parse it as JSON
    if (dataValue) {
        dataValue = JSON.parse(dataValue);
        if (pageType === "Article") {
            dataValue["lead_style"] = "medium";
        }
        if (!pageType) {
            pageType = dataValue["page_type"];
        }
    }
    // If pageType exists, update the event and pageType properties in dataValue
    if (pageType) {
        dataValue.event = "AP Configuration"; // Set the event property to "AP Configuration"
        dataValue.pageType = pageType; // Set the pageType property to the value obtained earlier
        if (dataValue.page_type) {
            delete dataValue.page_type
        }
        window.dataLayer.push(dataValue);
    }

})();

