window.Zephr = window.Zephr || {};
window.Zephr.includeOutcomes = true;
window.Zephr.outcomesAsEvents = true;
window.Zephr.groupFields = false;

(function() {
    console.log('loading blaize...');

    function waitForZephrAccessDetails(callback, timeout = 7000, interval = 500) {
        var elapsed = 0;

        var check = setInterval(function () {
            if (window.Zephr && window.Zephr.accessDetails) {
                clearInterval(check);
                callback();
            } else if (elapsed >= timeout) {
                clearInterval(check);
                console.warn('Zephr accessDetails not available after 7s, proceeding anyway...');
                callback(); // fallback
            }
            elapsed += interval;
        }, interval);
    }

    waitForZephrAccessDetails(function () {
        var xhr = new (XMLHttpRequest || ActiveXObject)('MSXML2.XMLHTTP.3.0');
        xhr.open('GET', '/blaize/datalayer', true);

        xhr.onreadystatechange = function() {
            if (xhr.readyState === 4) {
                var response;
                try {
                    response = JSON.parse(xhr.response);
                } catch (e) {
                    response = xhr.response;
                }

                if (xhr.status === 200) {
                    for (var dataLayerFieldName in response) {
                        if (!(dataLayerFieldName in window)) window[dataLayerFieldName] = [];

                        const zephrTrackingId = response[dataLayerFieldName].zephrActivity
                            ? response[dataLayerFieldName].zephrActivity.trackingId
                            : null;

                        window.localStorage.setItem('zephrTrackingId', zephrTrackingId);

                        var pageView = response[dataLayerFieldName];
                        var events = [];

                        if (window.Zephr && window.Zephr.includeOutcomes && window.Zephr.outcomes) {
                            pageView.zephrOutcomes = window.Zephr.outcomes;

                            if (window.Zephr.outcomesAsEvents) {
                                Object.keys(window.Zephr.outcomes || []).forEach(function(outcomeKey) {
                                    events.push({
                                        event: "zephr-outcome-" + outcomeKey,
                                        featureId: outcomeKey,
                                        featureLabel: window.Zephr.outcomes[outcomeKey].featureLabel,
                                        outcomeId: window.Zephr.outcomes[outcomeKey].outcomeId,
                                        outcomeLabel: window.Zephr.outcomes[outcomeKey].outcomeLabel,
                                    });
                                });
                            }
                        }

                        if (Object.keys(pageView).length) {
                            pageView.event = "zephr-pageview";
                            events.unshift(pageView);
                        }

                        if (!events.length) continue;

                        events.forEach(function(event) {
                            window[dataLayerFieldName].push(event);
                        });
                    }

                    var readyEvent = document.createEvent('Event');
                    readyEvent.initEvent('zephr.dataLayerReady', true, true);
                    document.dispatchEvent(readyEvent);
                }
            }
        };

        xhr.send({});
    });

})();

window.admiral("targeting", "pause");
let targetingReady = false;

// Detect if page is loaded in any mobile app WebView
function detectWebView() {
    const userAgent = navigator.userAgent || '';

    // Android WebView detection
    // Looks for "wv" flag or Android without Chrome mobile
    const isAndroidWebView = /wv/.test(userAgent) ||
        (/Android/.test(userAgent) && /Version\/[\d.]+/.test(userAgent) && !/Chrome\/[.0-9]* Mobile/.test(userAgent));

    // iOS WebView detection  
    // iOS devices with WebKit but NOT Safari (indicates in-app browser)
    const isIOSWebView = (/(iPhone|iPod|iPad)/.test(userAgent) && /AppleWebKit/.test(userAgent) && !/Safari/.test(userAgent)) ||
        // Additional patterns for iOS WebViews
        /(iPhone|iPod|iPad).*AppleWebKit(?!.*Safari)/i.test(userAgent);

    return {
        isWebView: isAndroidWebView || isIOSWebView,
        platform: isAndroidWebView ? 'android' : (isIOSWebView ? 'ios' : 'web')
    };
}

function setupAdmiralAuthTargeting() {
    if (targetingReady) return;

    // Detect WebView
    const webViewInfo = detectWebView();

    // Check for Zephr
    if (window.Zephr &&
        window.Zephr.accessDetails &&
        window.Zephr.accessDetails.authenticated !== undefined) {

        // Get authentication status
        const isAuthenticated = window.Zephr.accessDetails.authenticated;

        // Get activeProducts (donation status)
        const activeProducts = window.Zephr.accessDetails.activeProducts || [];
        const activeProductsString = activeProducts.length > 0 ? activeProducts.join(',') : 'none';

        // Check entitlements for the specific value '54OJxr'
        const entitlements = window.Zephr.accessDetails.entitlements;
        let has54OJxr = false;
        try {
            has54OJxr = !!entitlements && JSON.stringify(entitlements).includes('"54OJxr"');
        } catch (e) {
            has54OJxr = false;
        }

        // Set Admiral targeting parameters
        window.admiral("targeting", "set", "authenticated", isAuthenticated.toString());
        window.admiral("targeting", "set", "activeProducts", activeProductsString);
        window.admiral("targeting", "set", "entitled_54OJxr", has54OJxr.toString());
        window.admiral("targeting", "set", "isWebView", webViewInfo.isWebView.toString());
        window.admiral("targeting", "set", "webViewPlatform", webViewInfo.platform);

        window.admiral("targeting", "ready");
        targetingReady = true;

        console.log('Admiral targeting set: authenticated =', isAuthenticated);
        console.log('Admiral targeting set: activeProducts =', activeProductsString);
        console.log('Admiral targeting set: entitled_54OJxr =', has54OJxr);
        console.log('Admiral targeting set: isWebView =', webViewInfo.isWebView);
        console.log('Admiral targeting set: webViewPlatform =', webViewInfo.platform);
        console.log('Admiral User Agent:', navigator.userAgent);
    } else {
        // Zephr not ready yet, try again
        setTimeout(setupAdmiralAuthTargeting, 500);
    }
}

setupAdmiralAuthTargeting();

// Failsafe timeout 
setTimeout(function() {
    if (!targetingReady) {
        const webViewInfo = detectWebView();

        window.admiral("targeting", "set", "authenticated", "unknown");
        window.admiral("targeting", "set", "activeProducts", "unknown");
        window.admiral("targeting", "set", "entitled_54OJxr", "unknown");
        window.admiral("targeting", "set", "isWebView", webViewInfo.isWebView.toString());
        window.admiral("targeting", "set", "webViewPlatform", webViewInfo.platform);

        window.admiral("targeting", "ready");
        targetingReady = true;
        console.warn('Zephr authentication check timed out, proceeding with unknown status');
    }
}, 3000);

function onVFReady(callback) {
  const check = setInterval(() => {
    if (window.Zephr && window.vf?.session && typeof window.vf.session.logout === 'function') {
      clearInterval(check);
      callback();
    }
  }, 1000);
}

onVFReady(() => {
  console.log('viafoura: logging out');

  if (!window.Zephr?.accessDetails?.authenticated) {
    window.vf.session.logout();
  }
});

