link.script:
(function() {
    var hasFired = false;

    function getMeterValue() {
        if (!window.dataLayer) return null;
        for (var i = window.dataLayer.length - 1; i >= 0; i--) {
            if (window.dataLayer[i].content_meter_left !== undefined) {
                return parseInt(window.dataLayer[i].content_meter_left);
            }
        }
        return null;
    }

    function isWebView() {
        var ua = navigator.userAgent || '';
        var isAndroid = /wv/.test(ua) ||
            (/Android/.test(ua) && /Version\/[\d.]+/.test(ua) && !/Chrome\/[.0-9]* Mobile/.test(ua));
        var isIOS = (/(iPhone|iPod|iPad)/.test(ua) && /AppleWebKit/.test(ua) && !/Safari/.test(ua)) ||
            /(iPhone|iPod|iPad).*AppleWebKit(?!.*Safari)/i.test(ua);
        return isAndroid || isIOS;
    }

    function hasNoRegWallTag() {
        var meta = document.querySelector('meta[name="gtm-dataLayer"]');
        if (!meta) return false;
        try {
            var data = JSON.parse(meta.getAttribute('content'));
            if (data && data.tag_array) {
                var tags = data.tag_array.split(',');
                for (var i = 0; i < tags.length; i++) {
                    if (tags[i].trim().toLowerCase() === 'no reg wall') return true;
                }
            }
        } catch (e) {}
        return false;
    }

    function checkConditionsAndFire() {
        if (hasFired) return 'done';
        if (!window.blueConicClient) return 'waiting';

        var meterLeft = getMeterValue();
        if (meterLeft === null) return 'waiting';

        if (meterLeft > 0) return 'done';

        if (!window.Zephr || !window.Zephr.accessDetails) return 'waiting';
        if (window.Zephr.accessDetails.authenticated === true) return 'done';

        if (isWebView()) return 'done';

        if (hasNoRegWallTag()) return 'done';

        hasFired = true;
        window.blueConicClient.createEvent('METER_DIALOG_QUALIFIED');
        return 'done';
    }

    var interval = setInterval(function() {
        if (checkConditionsAndFire() === 'done') clearInterval(interval);
    }, 200);

    setTimeout(function() { clearInterval(interval); }, 10000);
})();

(function () {
    var regWallCookie = document.cookie
        .split('; ')
        .find(function (row) { return row.startsWith('RegWallAB01='); });
    if (regWallCookie) {
        var regWallValue = regWallCookie.split('=')[1];
        window.googletag = window.googletag || {};
        window.googletag.cmd = window.googletag.cmd || [];
        window.googletag.cmd.push(function () {
            window.googletag.pubads().setTargeting('regwall_ab', regWallValue);
        });
    }
})();

