link.script:
var link = document.createElement('link');
link.setAttribute('href', '//fonts.googleapis.com/css?family=Roboto:300,400,700|Merriweather:300,400,700&display=swap');
var relList = link.relList;

if (relList && relList.supports('preload')) {
    link.setAttribute('as', 'style');
    link.setAttribute('rel', 'preload');
    link.setAttribute('onload', 'this.rel="stylesheet"');
    link.setAttribute('crossorigin', 'anonymous');
} else {
    link.setAttribute('rel', 'stylesheet');
}

head.appendChild(link);

document.addEventListener('DOMContentLoaded', () => {
  const LOG = '[ZephrInit]'

  const runZephr = (attempt = 0) => {
    const available = typeof window.zephrBrowser !== 'undefined'
    console.log(`${LOG} attempt=${attempt} available=${available}`)

    if (!available) {
      if (attempt < 3) {
        setTimeout(() => runZephr(attempt + 1), 250)
      } else {
        console.warn(`${LOG} zephrBrowser not available after ${attempt + 1} attempts`)
      }
      return
    }

    try {window.zephrBrowser.run()} catch (e) {
      console.error(`${LOG} run error`, e)
    }
  }

  console.log('[ZephrInit] DOMContentLoaded, scheduling run')
  runZephr()
})

