freestar.queue.push(function() {
    let thisPlacement = "apnews_leaderboard";
    window.fsAdCounts = window.fsAdCounts || {};
    window.fsAdCounts[thisPlacement] = window.fsAdCounts[thisPlacement] + 1 || 0;
    let adList = document.getElementsByClassName(thisPlacement);
    if (adList.length <= window.fsAdCounts[thisPlacement] || adList[window.fsAdCounts[thisPlacement]].offsetParent === null) { return };
    let thisAd = adList[window.fsAdCounts[thisPlacement]];
    let randId = Math.random().toString(36).slice(2);
