or  inside the title, neutralize them too */
   .viafoura[data-ap-typography] .vf-item-layout__title u,
   .viafoura[data-ap-typography] .vf-item-layout__title ins,
   .viafoura[data-ap-typography] .vf-trending-article__title u,
   .viafoura[data-ap-typography] .vf-trending-article__title ins {
     text-decoration: none !important;
     border: 0 !important;
     background: none !important;
   }

   /* Block any “fancy underline” pseudo-elements */
   .viafoura[data-ap-typography] .vf-item-layout__title a::before,
   .viafoura[data-ap-typography] .vf-item-layout__title a::after,
   .viafoura[data-ap-typography] .vf-trending-article__title a::before,
   .viafoura[data-ap-typography] .vf-trending-article__title a::after,
   .viafoura[data-ap-typography] .vf-item-layout__title *::before,
   .viafoura[data-ap-typography] .vf-item-layout__title *::after,
   .viafoura[data-ap-typography] .vf-trending-article__title *::before,
   .viafoura[data-ap-typography] .vf-trending-article__title *::after {
     content: none !important;
     background: none !important;
     box-shadow: none !important;
     border: 0 !important;
   }
   /* Headline hover: remove underline at every layer AND stop the animation that causes the blink */
   .viafoura[data-ap-typography] .vf-item-layout__title,
   .viafoura[data-ap-typography] .vf-trending-article__title {
     text-decoration: none !important;
   }

   /* Neutralize hover/focus on the container, the , and ALL descendants */
   .viafoura[data-ap-typography] .vf-item-layout__title:is(:hover,:focus-within),
   .viafoura[data-ap-typography] .vf-trending-article__title:is(:hover,:focus-within),
   .viafoura[data-ap-typography] .vf-item-layout__title a:is(:hover,:focus),
   .viafoura[data-ap-typography] .vf-trending-article__title a:is(:hover,:focus),
   .viafoura[data-ap-typography] .vf-item-layout__title:is(:hover,:focus-within) *,
   .viafoura[data-ap-typography] .vf-trending-article__title:is(:hover,:focus-within) * {
     text-decoration: none !important;
     text-decoration-line: none !important;
     text-decoration-color: transparent !important;
     text-decoration-thickness: 0 !important;
     background: none !important;
     background-image: none !important;
     background-size: 0 0 !important; /* kills gradient-underlines that animate size */
     border-bottom: 0 !important;
     box-shadow: none !important;
     text-shadow: none !important;
     transition: none !important;      /* stop the “blink” caused by transitions */
     animation: none !important;       /* stop animated underline reveals */
   }

   /* Block pseudo-element underlines on hover/focus */
   .viafoura[data-ap-typography] .vf-item-layout__title *::before,
   .viafoura[data-ap-typography] .vf-item-layout__title *::after,
   .viafoura[data-ap-typography] .vf-trending-article__title *::before,
   .viafoura[data-ap-typography] .vf-trending-article__title *::after {
     content: none !important;
     background: none !important;
     background-image: none !important;
     background-size: 0 0 !important;
     border: 0 !important;
     box-shadow: none !important;
     transition: none !important;
     animation: none !important;
   }

